import { Link, useNavigate } from 'react-router-dom';

function Dashboard() {
  const navigate = useNavigate();

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('refreshToken');
    navigate('/');
  };

  return (
    <main className="app-shell">
      <nav className="topbar">
        <strong>Campus Event Manager</strong>
        <div>
          <Link to="/events">Events</Link>
          <button className="secondary" onClick={logout}>Logout</button>
        </div>
      </nav>

      <section className="page-header">
        <p className="eyebrow">Dashboard</p>
        <h1>Welcome back</h1>
        <p className="muted">Create events, browse active deadlines, and manage campus participation from one place.</p>
      </section>

      <section className="quick-grid">
        <Link className="action-card" to="/events">
          <span>Events</span>
          <strong>View and create events</strong>
        </Link>
      </section>
    </main>
  );
}

export default Dashboard;
